import React, { useState } from 'react';

function Committees() {
  const committeeData = [
    { 
      id: 'sac', 
      title: 'Students Affairs Committee', 
      short: 'SAC',
      objective: "The objective of SAC (Student Affairs Committee) is to provide a platform for student's activity in co-curricular and extracurricular activities, fostering their personal goal and enhancing their overall university experience.",
      formation: "The formation of the Student Affairs Committee aims to enhance student engagement, foster a vibrant campus culture, and provide opportunities for personal growth and skill development. Indus University has constituted the Student Affairs Committee for the year 2025-2027 with the following members.",
      members: [
        { name: "Dr. Ketan Lakhtaria (Dean, Student Affairs)", profession: "Chairman" },
      ],
      color: "bg-[#ffae4f]"
    },
    { id: 'activity', title: 'Students Activity Cell', short: 'Cell', objective: "Fostering institutional events and cultural celebrations.", color: "bg-slate-300" },
    { id: 'counseling', title: 'Student Counseling & Mentoring Cell', short: 'Mentoring', objective: "Psychological and academic support for students.", color: "bg-slate-300" },
    { id: 'grievance', title: 'University Student Grievance Redressal Committee', short: 'Redressal', objective: "Addressing institutional concerns and feedback.", color: "bg-slate-300" },
    { id: 'scst', title: 'SC/ST Committee', short: 'Equality', objective: "Ensuring equity and community support.", color: "bg-slate-300" },
    { id: 'anti-ragging', title: 'Anti-Ragging Committee', short: 'Safety', objective: "Maintaining a zero-tolerance policy against ragging.", color: "bg-slate-300" },
    { id: 'anti-squad', title: 'Anti-Ragging Squad', short: 'Squad', objective: "Active monitoring for campus safety.", color: "bg-slate-300" },
    { id: 'internal', title: 'Internal Complaint Committee', short: 'ICC', objective: "Handling workplace and academic complaints.", color: "bg-slate-300" },
    { id: 'women', title: 'Women\'s Development Cell', short: 'WDC', objective: "Empowerment and welfare programs.", color: "bg-slate-300" },
    { id: 'staff', title: 'Staff Grievance and Redressal Committee', short: 'Staff', objective: "Employee welfare and conflict resolution.", color: "bg-slate-300" },
    { id: 'advisory', title: 'Student Advisory', short: 'Advisory', objective: "Consultative body for student life.", color: "bg-slate-300" },
    { id: 'iqac', title: 'IQAC Committee', short: 'IQAC', objective: "Quality assurance and academic standards.", color: "bg-slate-300" },
    { id: 'purchase', title: 'Purchase Committee', short: 'Procurement', objective: "Institutional resource management.", color: "bg-slate-300" },
    { id: 'industry', title: 'Institution Industry Cell', short: 'IIC', objective: "Industry-academic collaboration.", color: "bg-slate-300" },
    { id: 'ombuds', title: 'Appointment of Ombudsperson', short: 'Ombuds', objective: "Independent mediation and oversight.", color: "bg-slate-300" },
  ];

  const [activeTab, setActiveTab] = useState('sac');
  const activeCommittee = committeeData.find(c => c.id === activeTab) || committeeData[0];

  return (
    <div className="fade-in w-full h-full flex flex-col">
      {/* Top Tabs Grid */}
      <div className="flex flex-wrap gap-1 mb-10 bg-slate-100 p-1 rounded-2xl">
        {committeeData.map((comm) => (
          <button
            key={comm.id}
            onClick={() => setActiveTab(comm.id)}
            className={`px-4 py-2 text-[11px] font-bold tracking-tight rounded-xl transition-all flex-1 min-w-[max-content]
              ${activeTab === comm.id 
                ? 'bg-[#ffae4f] text-slate-900 shadow-md transform -translate-y-0.5' 
                : 'bg-slate-200/50 text-slate-500 hover:bg-slate-200'}
            `}
          >
            {comm.title}
          </button>
        ))}
      </div>

      {/* Main Detail Area */}
      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col items-stretch flex-1 min-h-0">
        {/* Header Ribbon */}
        <div className="h-24 md:h-32 bg-[#ffae4f] flex items-center px-10 relative overflow-hidden">
             {/* Abstract Group Icon */}
             <div className="flex items-end gap-1 scale-[0.6] origin-left">
                <div className="w-12 h-12 rounded-full bg-slate-900"></div>
                <div className="w-16 h-20 rounded-t-full bg-slate-900 flex items-center justify-center">
                    <span className="text-white text-3xl">★</span>
                </div>
                <div className="w-12 h-12 rounded-full bg-slate-900"></div>
             </div>
             <h2 className="text-3xl font-black text-slate-900 ml-12 tracking-tight">{activeCommittee.title}</h2>
        </div>

        {/* Content Body */}
        <div className="p-10 md:p-12 overflow-y-auto custom-scrollbar flex-1">
          <div className="max-w-4xl space-y-8">
            <p className="text-lg font-bold text-slate-800 leading-relaxed italic opacity-90">
              "{activeCommittee.objective}"
            </p>

            {activeCommittee.formation && (
              <p className="text-slate-600 font-medium leading-relaxed leading-[1.8]">
                 {activeCommittee.formation}
              </p>
            )}

            {/* Members Table */}
            {activeCommittee.members && (
              <div className="mt-12 rounded-2xl border border-slate-100 overflow-hidden">
                <div className="grid grid-cols-2 bg-[#ffae4f]/20 p-4 border-b border-[#ffae4f]/10">
                  <span className="text-sm font-black uppercase tracking-widest text-slate-700">Name of the Member</span>
                  <span className="text-sm font-black uppercase tracking-widest text-slate-700">Profession</span>
                </div>
                <div className="divide-y divide-slate-50">
                  {activeCommittee.members.map((member, idx) => (
                    <div key={idx} className="grid grid-cols-2 p-5 bg-white items-center">
                       <span className="font-bold text-slate-800">{member.name}</span>
                       <span className="text-slate-600 font-medium">{member.profession}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {!activeCommittee.members && (
              <div className="py-20 text-center opacity-30 italic font-bold text-slate-400">
                Committee membership details are being updated for 2026.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Committees;
